// Validate retention trigger payload
const body = $input.first().json.body;

const required = ['customer_id', 'trigger_type'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const validTriggers = [
  'login_anomaly', 'portal_activity', 'renewal_upcoming',
  'competitor_signal', 'support_contact', 'payment_late', 'manual'
];

if (!validTriggers.includes(body.trigger_type)) {
  throw new Error(`Unknown trigger_type: ${body.trigger_type}. Valid: ${validTriggers.join(', ')}`);
}

return [{
  json: {
    customer_id: body.customer_id,
    trigger_type: body.trigger_type,
    trigger_detail: body.trigger_detail || null,
    triggered_at: new Date().toISOString(),
    pipeline: 'retention'
  }
}];

// Merge all customer data into retention agent input
const trigger = $('Validate Trigger').first().json;
const profile = $('Load Full Customer Profile').first().json || {};
const behavior = $('Load Behavioral Signals').first().json || {};

// Business key for this retention event (used by HITL review + outcome endpoints)
const retentionEventId = `RET-${trigger.customer_id}-${Date.now()}`;

const enriched = {
  retention_event_id: retentionEventId,
  customer_id: trigger.customer_id,
  trigger_type: trigger.trigger_type,
  trigger_detail: trigger.trigger_detail,
  // Profile
  customer_name: profile.full_name || null,
  segment: profile.segment || null,
  customer_since_years: profile.years_as_customer || null,
  annual_premium: profile.total_annual_premium || null,
  policy_count: profile.active_policy_count || null,
  policy_types: profile.policy_types || [],
  last_claim_months_ago: profile.last_claim_months_ago || null,
  total_claims_ever: profile.total_claims_count || null,
  nps_score: profile.nps_score || null,
  renewal_due_days: profile.next_renewal_days || null,
  customer_ltv: profile.ltv_estimate || null,
  // Behavioral
  portal_logins: behavior.portal_logins_30d || null,
  contract_views: behavior.contract_page_views_30d || null,
  competitor_portal_visits: behavior.competitor_visits_30d || null,
  support_contacts: behavior.support_contacts_30d || null,
  email_open_rate: behavior.email_open_rate_30d || null
};
return [{ json: enriched }];

// Orchestrator: apply business rules on top of agent result
const agent = $json;
const context = $('Build Agent Context').first().json;

let finalRoute = agent.recommended_route;
let overrideReason = null;

// Rule 1: VIP customer (LTV > CHF 50k) always gets call task regardless of score
if (context.customer_ltv > 50000 && finalRoute !== 'call_task' && agent.churn_score >= 0.30) {
  finalRoute = 'call_task';
  overrideReason = `High-value customer (LTV CHF ${context.customer_ltv.toLocaleString()}) — escalated to call task`;
}

// Rule 2: Critical churn risk with < 30 days to renewal always gets offer
if (agent.churn_risk_level === 'critical' && context.renewal_due_days <= 30) {
  // Keep call_task if already set, but ensure offer is also generated
  overrideReason = overrideReason || 'Critical churn + renewal < 30 days — dual action';
}

// Rule 3: No-action is only valid if churn_score < 0.20 AND no renewal < 45 days
if (finalRoute === 'no_action' && context.renewal_due_days <= 45) {
  finalRoute = 'automated_campaign';
  overrideReason = 'Renewal approaching — automated campaign triggered regardless of churn score';
}

return [{
  json: {
    ...agent,
    final_route: finalRoute,
    orchestrator_override: finalRoute !== agent.recommended_route,
    override_reason: overrideReason,
    orchestrated_at: new Date().toISOString()
  }
}];

// CALL TASK: Create priority call task in CRM
const data = $json;
return [{
  json: {
    action: 'call_task',
    customer_id: data.customer_id,
    priority: data.priority_score > 70 ? 'HIGH' : 'MEDIUM',
    churn_score: data.churn_score,
    churn_risk_level: data.churn_risk_level,
    offer_type: data.offer_type,
    offer_suggestion: data.offer_value_suggestion,
    reasoning_summary: data.reasoning,
    flags: data.flags,
    assign_to: data.priority_score > 80 ? 'senior_account_manager' : 'account_manager',
    due_within_hours: data.churn_risk_level === 'critical' ? 4 : 24,
    message: `Priority call required: Customer ${data.customer_id}, churn score ${data.churn_score.toFixed(2)}`,
    created_at: new Date().toISOString()
  }
}];

// GENERATE OFFER: Trigger Offer Pipeline via webhook
const data = $json;
return [{
  json: {
    action: 'generate_offer',
    customer_id: data.customer_id,
    source_pipeline: 'retention',
    churn_score: data.churn_score,
    offer_type_hint: data.offer_type,
    offer_value_suggestion: data.offer_value_suggestion,
    campaign_segment: data.campaign_segment,
    urgency: data.churn_risk_level === 'critical' ? 'high' : 'medium',
    message: `Offer generation triggered for ${data.customer_id} (retention)`,
    created_at: new Date().toISOString()
  }
}];

// AUTOMATED CAMPAIGN: Trigger email/push campaign
const data = $json;
return [{
  json: {
    action: 'automated_campaign',
    customer_id: data.customer_id,
    campaign_segment: data.campaign_segment || 'standard_retention',
    churn_score: data.churn_score,
    message: `Automated retention campaign triggered for ${data.customer_id}`,
    channel: 'email',
    created_at: new Date().toISOString()
  }
}];

